from __future__ import annotations

import os
import random
import time
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, List, Optional


@dataclass
class GenerationConfig:
    count: int = 5
    seed: int = 1337
    backend: str = "template"
    model: str = "gpt-4o-mini"
    prompt_template: str = (
        "Generate a single valid LLVM IR function. "
        "Return only LLVM IR, no prose.\n"
        "Constraints: SSA form, i32 ops, and end with ret."
    )


TEMPLATES: List[str] = [
    """define i32 @add_const_{id}(i32 %x) {{
entry:
  %v = add i32 %x, {c}
  ret i32 %v
}}\n""",
    """define i32 @mul_const_{id}(i32 %x) {{
entry:
  %v = mul i32 %x, {c}
  ret i32 %v
}}\n""",
    """define i32 @max_{id}(i32 %a, i32 %b) {{
entry:
  %cmp = icmp sgt i32 %a, %b
  br i1 %cmp, label %then, label %else
then:
  br label %merge
else:
  br label %merge
merge:
  %res = phi i32 [ %a, %then ], [ %b, %else ]
  ret i32 %res
}}\n""",
]


def _openai_generate(prompt: str, model: str) -> Optional[str]:
    if not os.getenv("OPENAI_API_KEY"):
        return None
    try:
        from openai import OpenAI
    except Exception:
        return None

    try:
        client = OpenAI()
        response = client.responses.create(
            model=model,
            input=prompt,
        )
    except Exception:
        return None

    text_chunks = []
    for item in response.output:
        if item.type == "message":
            for content in item.content:
                if content.type == "output_text":
                    text_chunks.append(content.text)
    return "\n".join(text_chunks).strip() if text_chunks else None


def generate_ir_snippets(config: GenerationConfig) -> Iterable[str]:
    rng = random.Random(config.seed)
    if config.backend == "openai":
        for i in range(config.count):
            prompt = f"{config.prompt_template}\n\n; id: {i}\n"
            result = _openai_generate(prompt, config.model)
            if result:
                yield result + "\n"
            else:
                template = rng.choice(TEMPLATES)
                const_val = rng.randint(1, 9)
                yield template.format(id=i, c=const_val)
        return

    for i in range(config.count):
        template = rng.choice(TEMPLATES)
        const_val = rng.randint(1, 9)
        yield template.format(id=i, c=const_val)


def write_generated_ir(output_dir: Path, config: GenerationConfig) -> List[Path]:
    output_dir.mkdir(parents=True, exist_ok=True)
    created: List[Path] = []
    timestamp = int(time.time())
    for idx, snippet in enumerate(generate_ir_snippets(config)):
        file_path = output_dir / f"gen_{timestamp}_{idx}.ll"
        file_path.write_text(snippet)
        created.append(file_path)
    return created

from __future__ import annotations

import os
import random
import time
from dataclasses import dataclass
from pathlib import Path
from typing import Iterable, List, Optional


@dataclass
class GenerationConfig:
    count: int = 5
    seed: int = 1337
    backend: str = "template"
    model: str = "gpt-4o-mini"
    prompt_template: str = (
        "Generate a single valid LLVM IR function. "
        "Return only LLVM IR, no prose.\n"
        "Constraints: SSA form, i32 ops, and end with ret."
    )


TEMPLATES: List[str] = [
    """define i32 @add_const_{id}(i32 %x) {{
entry:
  %v = add i32 %x, {c}
  ret i32 %v
}}\n""",
    """define i32 @mul_const_{id}(i32 %x) {{
entry:
  %v = mul i32 %x, {c}
  ret i32 %v
}}\n""",
    """define i32 @max_{id}(i32 %a, i32 %b) {{
entry:
  %cmp = icmp sgt i32 %a, %b
  br i1 %cmp, label %then, label %else
then:
  br label %merge
else:
  br label %merge
merge:
  %res = phi i32 [ %a, %then ], [ %b, %else ]
  ret i32 %res
}}\n""",
]


_ENV_LOADED = False


def _load_dotenv() -> None:
    global _ENV_LOADED
    if _ENV_LOADED:
        return
    env_path = Path.cwd() / ".env"
    if not env_path.exists():
        _ENV_LOADED = True
        return
    for line in env_path.read_text().splitlines():
        line = line.strip()
        if not line or line.startswith("#") or "=" not in line:
            continue
        key, value = line.split("=", 1)
        key = key.strip()
        value = value.strip().strip('"').strip("'")
        os.environ.setdefault(key, value)
    _ENV_LOADED = True


def _openai_generate(prompt: str, model: str) -> Optional[str]:
    _load_dotenv()
    if not os.getenv("OPENAI_API_KEY"):
        return None
    try:
        from openai import OpenAI
    except Exception:
        return None

    try:
        client = OpenAI()
        response = client.responses.create(
            model=model,
            input=prompt,
        )
    except Exception:
        return None

    text_chunks = []
    for item in response.output:
        if item.type == "message":
            for content in item.content:
                if content.type == "output_text":
                    text_chunks.append(content.text)
    return "\n".join(text_chunks).strip() if text_chunks else None


def generate_ir_snippets(config: GenerationConfig) -> Iterable[str]:
    rng = random.Random(config.seed)
    if config.backend == "openai":
        for i in range(config.count):
            prompt = f"{config.prompt_template}\n\n; id: {i}\n"
            result = _openai_generate(prompt, config.model)
            if result:
                yield result + "\n"
            else:
                template = rng.choice(TEMPLATES)
                const_val = rng.randint(1, 9)
                yield template.format(id=i, c=const_val)
        return

    for i in range(config.count):
        template = rng.choice(TEMPLATES)
        const_val = rng.randint(1, 9)
        yield template.format(id=i, c=const_val)


def write_generated_ir(output_dir: Path, config: GenerationConfig) -> List[Path]:
    output_dir.mkdir(parents=True, exist_ok=True)
    created: List[Path] = []
    timestamp = int(time.time())
    for idx, snippet in enumerate(generate_ir_snippets(config)):
        file_path = output_dir / f"gen_{timestamp}_{idx}.ll"
        file_path.write_text(snippet)
